import redis

# Connect to Redis server
r = redis.Redis(host='localhost', port=6379, db=0)

def execute_lua_script():
    lua_code = input("Enter your LUA script: ")
    
    # Get user parameters for the Lua script
    num_params = int(input("Enter number of parameters: "))
    params = []
    for i in range(num_params):
        param = input(f"Enter parameter {i+1}: ")
        params.append(param)
    
    # Execute Lua script with user-provided parameters
    result = r.eval(lua_code, num_keys=0, args=tuple(params))
    print("Result: ", result)

execute_lua_script()